// Package main is the entry point for the go-project E2E test fixture.
package main

import (
	"encoding/json"
	"fmt"
	"log"
	"net/http"
)

// buildMux assembles the application's ServeMux. Extracted so handlers can
// be unit-tested via net/http/httptest without binding a real listener.
func buildMux() *http.ServeMux {
	mux := http.NewServeMux()

	mux.HandleFunc("/", func(w http.ResponseWriter, r *http.Request) {
		if r.URL.Path != "/" {
			http.NotFound(w, r)
			return
		}
		w.WriteHeader(http.StatusOK)
		fmt.Fprint(w, "Hello, World!")
	})

	mux.HandleFunc("/goodbye", func(w http.ResponseWriter, r *http.Request) {
		w.Header().Set("Content-Type", "application/json")
		w.WriteHeader(http.StatusOK)
		_ = json.NewEncoder(w).Encode(map[string]string{"message": "Goodbye, World!"})
	})

	return mux
}

func main() {
	log.Println("Starting server on :8080")
	if err := http.ListenAndServe(":8080", buildMux()); err != nil {
		log.Fatal(err)
	}
}
GOEOF
"}
